 1→using System;
 2→using System.IO;
 3→using System.Text.Json;
 4→
 5→namespace PortableTestMachine2.Core;
 6→
 7→/// <summary>
 8→/// 애플리케이션 설정 (JSON 직렬화)
 9→/// </summary>
10→public class AppConfig
11→{
12→    /// <summary>파워서플라이 시리얼 포트</summary>
13→    public string PowerSupplyPort { get; set; } = "COM3";
14→
15→    /// <summary>IO 보드 시리얼 포트</summary>
16→    public string IoBoardPort { get; set; } = "COM4";
17→
18→    /// <summary>자동 검사 전압 (V)</summary>
19→    public double AutoVolt { get; set; } = 12.0;
20→
21→    /// <summary>자동 검사 횟수</summary>
22→    public int AutoCount { get; set; } = 5;
23→
24→    /// <summary>자동 정지 모드 ("CURRENT" 또는 "TIME")</summary>
25→    public string AutoStopMode { get; set; } = "CURRENT";
26→
27→    /// <summary>자동 정지 기준값</summary>
28→    public double AutoStopValue { get; set; } = 0.5;
29→
30→    /// <summary>수동 검사 전압 (V)</summary>
31→    public double ManualVolt { get; set; } = 12.0;
32→
33→    private static readonly JsonSerializerOptions JsonOptions = new()
34→    {
35→        WriteIndented = true
36→    };
37→
38→    /// <summary>
39→    /// 설정 파일에서 로드. 파일이 없으면 기본값 반환.
40→    /// </summary>
41→    public static AppConfig Load()
42→    {
43→        try
44→        {
45→            var path = PathManager.ConfigFilePath;
46→            if (!File.Exists(path))
47→                return new AppConfig();
48→
49→            var json = File.ReadAllText(path);
50→            return JsonSerializer.Deserialize<AppConfig>(json, JsonOptions) ?? new AppConfig();
51→        }
52→        catch (Exception ex)
53→        {
54→            Logger.Error("설정 파일 로드 실패, 기본값 사용", ex);
55→            return new AppConfig();
56→        }
57→    }
58→
59→    /// <summary>
60→    /// 설정을 JSON 파일로 저장
61→    /// </summary>
62→    public static void Save(AppConfig config)
63→    {
64→        try
65→        {
66→            PathManager.EnsureDirectories();
67→            var json = JsonSerializer.Serialize(config, JsonOptions);
68→            File.WriteAllText(PathManager.ConfigFilePath, json);
69→        }
70→        catch (Exception ex)
71→        {
72→            Logger.Error("설정 파일 저장 실패", ex);
73→        }
74→    }
75→}
