 1→using System;
 2→using System.IO;
 3→
 4→namespace PortableTestMachine2.Core;
 5→
 6→/// <summary>
 7→/// 스레드 안전 로거 (일별 로그 파일 + 크래시 로그)
 8→/// </summary>
 9→public static class Logger
10→{
11→    private static readonly object Lock = new();
12→
13→    /// <summary>
14→    /// 정보 레벨 로그 기록
15→    /// </summary>
16→    public static void Info(string message)
17→    {
18→        WriteLog("INFO", message);
19→    }
20→
21→    /// <summary>
22→    /// 에러 레벨 로그 기록
23→    /// </summary>
24→    public static void Error(string message, Exception? ex = null)
25→    {
26→        var text = ex != null ? $"{message} | {ex.GetType().Name}: {ex.Message}" : message;
27→        WriteLog("ERROR", text);
28→    }
29→
30→    /// <summary>
31→    /// 크래시 로그 기록 (전체 스택 트레이스 포함)
32→    /// </summary>
33→    public static void WriteCrashLog(Exception ex)
34→    {
35→        try
36→        {
37→            PathManager.EnsureDirectories();
38→            var entry = $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {ex.GetType().FullName}: {ex.Message}{Environment.NewLine}{ex.StackTrace}{Environment.NewLine}{Environment.NewLine}";
39→
40→            lock (Lock)
41→            {
42→                File.AppendAllText(PathManager.CrashLogPath, entry);
43→            }
44→        }
45→        catch
46→        {
47→            // 크래시 로그 기록 실패 시 무시 (이중 예외 방지)
48→        }
49→    }
50→
51→    /// <summary>
52→    /// 일별 로그 파일에 메시지 기록
53→    /// </summary>
54→    private static void WriteLog(string level, string message)
55→    {
56→        try
57→        {
58→            PathManager.EnsureDirectories();
59→            var fileName = $"{DateTime.Now:yyyy-MM-dd}.log";
60→            var filePath = Path.Combine(PathManager.LogDir, fileName);
61→            var entry = $"[{DateTime.Now:HH:mm:ss}] [{level}] {message}{Environment.NewLine}";
62→
63→            lock (Lock)
64→            {
65→                File.AppendAllText(filePath, entry);
66→            }
67→        }
68→        catch
69→        {
70→            // 로그 기록 실패 시 무시 (무한 재귀 방지)
71→        }
72→    }
73→}
