  1→using System.IO.Ports;
  2→using System.Text;
  3→
  4→namespace PortableTestMachine2.Communication;
  5→
  6→/// <summary>
  7→/// SCPI 전원공급기 통신 서비스
  8→/// 전류 측정 및 전압 설정을 폴링 방식으로 처리
  9→/// </summary>
 10→public class PowerSupplyService : IDeviceService
 11→{
 12→    private SerialPort? _port;
 13→    private bool _isConnected;
 14→    private readonly StringBuilder _recvBuffer = new();
 15→    private double _currentValue;
 16→    private double _targetVolt;
 17→    private readonly object _lock = new();
 18→
 19→    // 요청 단계 폴링 상태
 20→    private int _requestStep;
 21→    private DateTime _stepStartTime;
 22→
 23→    /// <summary>
 24→    /// 연결 상태
 25→    /// </summary>
 26→    public bool IsConnected => _isConnected;
 27→
 28→    /// <summary>
 29→    /// 측정된 전류값 (스레드 안전)
 30→    /// </summary>
 31→    public double CurrentValue
 32→    {
 33→        get { lock (_lock) return _currentValue; }
 34→        private set { lock (_lock) _currentValue = value; }
 35→    }
 36→
 37→    /// <summary>
 38→    /// 목표 전압값 (스레드 안전, 설정 시 전압 명령 전송)
 39→    /// </summary>
 40→    public double TargetVolt
 41→    {
 42→        get { lock (_lock) return _targetVolt; }
 43→        set
 44→        {
 45→            lock (_lock) _targetVolt = value;
 46→            SendSetVoltageCommand(value);
 47→        }
 48→    }
 49→
 50→    /// <summary>
 51→    /// 시리얼 포트 연결 및 초기화 명령 전송
 52→    /// </summary>
 53→    public bool Connect(string portName)
 54→    {
 55→        try
 56→        {
 57→            _port = new SerialPort(portName)
 58→            {
 59→                BaudRate = PowerSupplyProtocol.BAUD_RATE,
 60→                DataBits = 8,
 61→                Parity = Parity.None,
 62→                StopBits = StopBits.One,
 63→                Handshake = Handshake.XOnXOff
 64→            };
 65→
 66→            _port.DataReceived += Port_DataReceived;
 67→            _port.Open();
 68→
 69→            // 초기화 명령 전송
 70→            _port.Write(PowerSupplyProtocol.INIT_COMMAND + PowerSupplyProtocol.TERMINATOR);
 71→
 72→            _isConnected = true;
 73→            _requestStep = 0;
 74→            _stepStartTime = DateTime.Now;
 75→            return true;
 76→        }
 77→        catch
 78→        {
 79→            _isConnected = false;
 80→            return false;
 81→        }
 82→    }
 83→
 84→    /// <summary>
 85→    /// 연결 해제
 86→    /// </summary>
 87→    public void Disconnect()
 88→    {
 89→        try
 90→        {
 91→            if (_port != null)
 92→            {
 93→                _port.DataReceived -= Port_DataReceived;
 94→                if (_port.IsOpen)
 95→                    _port.Close();
 96→                _port.Dispose();
 97→                _port = null;
 98→            }
 99→        }
100→        catch
101→        {
102→            // 안전한 종료
103→        }
104→        finally
105→        {
106→            _isConnected = false;
107→        }
108→    }
109→
110→    /// <summary>
111→    /// 수신 데이터 처리 — CR(13) 수신 시 전류값 파싱
112→    /// </summary>
113→    private void Port_DataReceived(object sender, SerialDataReceivedEventArgs e)
114→    {
115→        if (_port == null || !_port.IsOpen) return;
116→
117→        try
118→        {
119→            int bytesToRead = _port.BytesToRead;
120→            byte[] buffer = new byte[bytesToRead];
121→            _port.Read(buffer, 0, bytesToRead);
122→
123→            lock (_lock)
124→            {
125→                foreach (byte b in buffer)
126→                {
127→                    if (b == PowerSupplyProtocol.RESPONSE_TERMINATOR)
128→                    {
129→                        // CR 수신 — 버퍼 내용을 전류값으로 파싱
130→                        string response = _recvBuffer.ToString();
131→                        _recvBuffer.Clear();
132→
133→                        if (PowerSupplyProtocol.TryParseCurrentResponse(response, out double value))
134→                        {
135→                            _currentValue = value;
136→                        }
137→
138→                        // 응답 수신 완료 → 다음 단계로 전환
139→                        if (_requestStep == 1)
140→                        {
141→                            _requestStep = 2;
142→                            _stepStartTime = DateTime.Now;
143→                        }
144→                    }
145→                    else
146→                    {
147→                        _recvBuffer.Append((char)b);
148→                    }
149→                }
150→            }
151→        }
152→        catch
153→        {
154→            // 수신 오류 무시
155→        }
156→    }
157→
158→    /// <summary>
159→    /// 전류 측정 요청 명령 전송
160→    /// </summary>
161→    public void SendMeasureCurrentCommand()
162→    {
163→        if (_port == null || !_port.IsOpen) return;
164→        _port.Write(PowerSupplyProtocol.MEASURE_CURRENT + PowerSupplyProtocol.TERMINATOR);
165→    }
166→
167→    /// <summary>
168→    /// 전압 설정 명령 전송
169→    /// </summary>
170→    public void SendSetVoltageCommand(double volt)
171→    {
172→        if (_port == null || !_port.IsOpen) return;
173→        _port.Write(PowerSupplyProtocol.BuildSetVoltageCommand(volt));
174→    }
175→
176→    /// <summary>
177→    /// 외부 타이머에서 호출 — 요청 단계 폴링 진행
178→    /// Step 0: 전류 측정 요청 → Step 1
179→    /// Step 1: 응답 대기 (DataReceived에서 처리) → Step 2
180→    /// Step 2: 전압 설정 전송 → Step 0
181→    /// 타임아웃: Step 1이 2초 초과 시 Step 0으로 리셋
182→    /// </summary>
183→    public void Poll()
184→    {
185→        if (!_isConnected) return;
186→
187→        lock (_lock)
188→        {
189→            switch (_requestStep)
190→            {
191→                case 0:
192→                    // 전류 측정 요청
193→                    SendMeasureCurrentCommand();
194→                    _requestStep = 1;
195→                    _stepStartTime = DateTime.Now;
196→                    break;
197→
198→                case 1:
199→                    // 응답 대기 — 타임아웃 확인
200→                    double elapsed = (DateTime.Now - _stepStartTime).TotalSeconds;
201→                    if (elapsed > PowerSupplyProtocol.TIMEOUT_SECONDS)
202→                    {
203→                        // 타임아웃 — 초기 단계로 리셋
204→                        _recvBuffer.Clear();
205→                        _requestStep = 0;
206→                    }
207→                    break;
208→
209→                case 2:
210→                    // 전압 설정 전송
211→                    SendSetVoltageCommand(_targetVolt);
212→                    _requestStep = 0;
213→                    _stepStartTime = DateTime.Now;
214→                    break;
215→            }
216→        }
217→    }
218→
219→    /// <summary>
220→    /// 리소스 해제
221→    /// </summary>
222→    public void Dispose()
223→    {
224→        Disconnect();
225→        GC.SuppressFinalize(this);
226→    }
227→}
