  5→/// <summary>
  6→/// IO 보드 통신 서비스
  7→/// DO 출력 제어 (CW/CCW 모터 방향 제어)
  8→/// </summary>
  9→public class IoBoardService : IDeviceService
 10→{
 11→    private SerialPort? _port;
 12→    private bool _isConnected;
 13→    private readonly char[] _doState = new char[IoBoardProtocol.DO_COUNT];
 14→    private readonly object _lock = new();
 15→
 16→    public IoBoardService()
 17→    {
 18→        // DO 상태 초기화 — 모두 '0'
 19→        Array.Fill(_doState, '0');
 20→    }
 21→
 22→    /// <summary>
 23→    /// 연결 상태
 24→    /// </summary>
 25→    public bool IsConnected => _isConnected;
 26→
 27→    /// <summary>
 28→    /// 시리얼 포트 연결
 29→    /// </summary>
 30→    public bool Connect(string portName)
 31→    {
 32→        try
 33→        {
 34→            _port = new SerialPort(portName)
 35→            {
 36→                BaudRate = IoBoardProtocol.BAUD_RATE,
 37→                DataBits = 8,
 38→                Parity = Parity.None,
 39→                StopBits = StopBits.One,
 40→                Handshake = Handshake.None
 41→            };
 42→
 43→            _port.Open();
 44→            _isConnected = true;
 45→            return true;
 46→        }
 47→        catch
 48→        {
 49→            _isConnected = false;
 50→            return false;
 51→        }
 52→    }
 53→
 54→    /// <summary>
 55→    /// 연결 해제
 56→    /// </summary>
 57→    public void Disconnect()
 58→    {
 59→        try
 60→        {
 61→            if (_port != null)
 62→            {
 63→                if (_port.IsOpen)
 64→                    _port.Close();
 65→                _port.Dispose();
 66→                _port = null;
 67→            }
 68→        }
 69→        catch
 70→        {
 71→            // 안전한 종료
 72→        }
 73→        finally
 74→        {
 75→            _isConnected = false;
 76→        }
 77→    }
 78→
 79→    /// <summary>
 80→    /// 개별 DO 출력 설정
 81→    /// </summary>
 82→    public void SetDo(int index, char value)
 83→    {
 84→        lock (_lock)
 85→        {
 86→            if (index >= 0 && index < IoBoardProtocol.DO_COUNT)
 87→            {
 88→                _doState[index] = value;
 89→            }
 90→        }
 91→    }
 92→
 93→    /// <summary>
 94→    /// 현재 DO 상태로 프레임 문자열 생성
 95→    /// </summary>
 96→    public string GetDoFrame()
 97→    {
 98→        lock (_lock)
 99→        {
100→            return IoBoardProtocol.BuildFrame(_doState);
101→        }
102→    }
103→
104→    /// <summary>
105→    /// DO 프레임을 시리얼 포트로 전송
106→    /// </summary>
107→    public void SendDoFrame()
108→    {
109→        if (_port == null || !_port.IsOpen) return;
110→
111→        lock (_lock)
112→        {
113→            string frame = IoBoardProtocol.BuildFrame(_doState);
114→            _port.Write(frame);
115→        }
116→    }
117→
118→    /// <summary>
119→    /// 모터 CW(정회전) — DO[0]=1, DO[1]=0
120→    /// </summary>
121→    public void CW()
122→    {
123→        lock (_lock)
124→        {
125→            _doState[IoBoardProtocol.CW_INDEX] = '1';
126→            _doState[IoBoardProtocol.CCW_INDEX] = '0';
127→        }
128→    }
129→
130→    /// <summary>
131→    /// 모터 CCW(역회전) — DO[0]=0, DO[1]=1
132→    /// </summary>
133→    public void CCW()
134→    {
135→        lock (_lock)
136→        {
137→            _doState[IoBoardProtocol.CW_INDEX] = '0';
138→            _doState[IoBoardProtocol.CCW_INDEX] = '1';
139→        }
140→    }
141→
142→    /// <summary>
143→    /// 모터 OFF(정지) — DO[0]=0, DO[1]=0
144→    /// </summary>
145→    public void OFF()
146→    {
147→        lock (_lock)
148→        {
149→            _doState[IoBoardProtocol.CW_INDEX] = '0';
150→            _doState[IoBoardProtocol.CCW_INDEX] = '0';
151→        }
152→    }
153→
154→    /// <summary>
155→    /// 리소스 해제
156→    /// </summary>
157→    public void Dispose()
158→    {
159→        Disconnect();
160→        GC.SuppressFinalize(this);
161→    }
162→}
