 1→using ClosedXML.Excel;
 2→using PortableTestMachine2.Models;
 3→
 4→namespace PortableTestMachine2.Data;
 5→
 6→/// <summary>
 7→/// 측정 결과를 엑셀 파일로 내보내기
 8→/// </summary>
 9→public static class ExcelExporter
10→{
11→    /// <summary>
12→    /// 측정 결과 리스트를 엑셀 파일로 저장
13→    /// </summary>
14→    public static void Export(List<MeasureResult> results, string filePath)
15→    {
16→        using var workbook = new XLWorkbook();
17→        var sheet = workbook.Worksheets.Add("검사결과");
18→
19→        // 헤더 설정
20→        string[] headers = ["No", "Info", "Volt(V)", "Current Max(A)", "Time(s)"];
21→        double[] widths = [8, 20, 12, 16, 12];
22→
23→        for (int i = 0; i < headers.Length; i++)
24→        {
25→            var cell = sheet.Cell(1, i + 1);
26→            cell.Value = headers[i];
27→            cell.Style.Font.Bold = true;
28→            cell.Style.Alignment.Horizontal = XLAlignmentHorizontalValues.Center;
29→            sheet.Column(i + 1).Width = widths[i];
30→        }
31→
32→        // 데이터 행 작성
33→        for (int row = 0; row < results.Count; row++)
34→        {
35→            var r = results[row];
36→            int excelRow = row + 2; // 헤더 다음 행부터
37→
38→            sheet.Cell(excelRow, 1).Value = row + 1;          // No (1부터 자동 번호)
39→            sheet.Cell(excelRow, 2).Value = r.Info;            // Info
40→            sheet.Cell(excelRow, 3).Value = r.Voltage;         // Volt(V)
41→            sheet.Cell(excelRow, 4).Value = r.MaxCurrent;      // Current Max(A)
42→            sheet.Cell(excelRow, 5).Value = r.ElapsedTime;     // Time(s)
43→        }
44→
45→        workbook.SaveAs(filePath);
46→    }
47→}
